    28→	public async getTrendingProductsByCategory({
    29→		categoryId,
    30→		excludeProductIds,
    31→		limit = 12,
    32→		offset = 0,
    33→	}: {
    34→		categoryId: number;
    35→		excludeProductIds?: number[];
    36→		limit?: number;
    37→		offset?: number;
    38→	}): Promise<TrendingProductsByCategoryResponseDto> {
    39→		try {
    40→			const params: {
    41→				categoryId: number;
    42→				excludeProductIds?: number[];
    43→				limit?: number;
    44→				offset?: number;
    45→			} = { categoryId, limit, offset };
    46→
    47→			if (excludeProductIds) params.excludeProductIds = excludeProductIds;
    48→
    49→			const trendingProductsList =
    50→				await this.forecastedTrendingProductsService.getTrendingProductsByCategory(
    51→					params,
    52→				);
    53→
    54→			const styleIds = trendingProductsList.map((item) => item.style_id);
    55→
    56→			const { products, mvRecords } =
    57→				await this.productHydrationService.hydrateProductsWithColors({
    58→					styleIds,
    59→				});
    60→
    61→			this.logger.debug('MV returned products', {
    62→				categoryId,
    63→				returnedCount: products.length,
    64→				requestedCount: trendingProductsList.length,
    65→			});
    66→
    67→			const trendingProducts = products.map((product) => {
    68→				const mv = mvRecords.get(product.style_id);
    69→				const colors = this.productHydrationService.convertMvColorsToProductColors(
    70→					mv?.colors ?? null,
    71→				);
    72→				return assignRandomColorToProduct(product, colors);
    73→			});
    74→
    75→			return { trendingProducts, categoryId };
    76→		} catch (error) {
    77→			this.logger.error(
    78→				`Error fetching trending products for category ${categoryId}: ${(error as Error).message}`,
    79→				(error as Error).stack,
    80→			);
    81→			throw error;
    82→		}
    83→	}
