    97→	public async getStyleIdsInDateRange({
    98→		startDate,
    99→		endDate,
   100→	}: {
   101→		startDate: string;
   102→		endDate: string;
   103→	}): Promise<IProductAnnualSalesBase[]> {
   104→		const startYearStr = startDate.split('-')[0];
   105→		const endYearStr = endDate.split('-')[0];
   106→
   107→		if (!startYearStr || !endYearStr) {
   108→			throw new Error(`Invalid date format: startDate=${startDate}, endDate=${endDate}`);
   109→		}
   110→
   111→		const startYear = parseInt(startYearStr, 10);
   112→		const endYear = parseInt(endYearStr, 10);
   113→
   114→		this.logger.log('Fetching style IDs from year range', { startYear, endYear });
   115→		return await this.productAnnualSalesService.findByYearRange({ startYear, endYear });
   116→	}
