   118→	public forecastStyleTrend({
   119→		styleId,
   120→		historicalData,
   121→		startDate,
   122→		endDate,
   123→		forecastDays,
   124→		bar,
   125→	}: {
   126→		styleId: number;
   127→		historicalData: IProductAnnualSalesBase[];
   128→		startDate: string;
   129→		endDate: string;
   130→		forecastDays: number;
   131→		bar?: ProgressBar;
   132→	}): CompleteForecastResult | null {
   133→		try {
   134→			const endDateDayNumber = this.getDayOfYear(new Date(endDate));
   135→
   136→			const purchasesArr = historicalData.reduce<number[]>((acc, data, index) => {
   137→				if (index === historicalData.length - 1) {
   138→					acc.push(...data.daily_orders.slice(0, endDateDayNumber));
   139→				} else {
   140→					acc.push(...data.daily_orders);
   141→				}
   142→				return acc;
   143→			}, []);
   144→
   145→			const smoothedPurchasesArr = MathematicalFunctions.exponentialSmoothing({
   146→				values: purchasesArr,
   147→				alpha: 0.1,
   148→			});
   149→
   150→			const harmonics = this.getHarmonicsByObservationsCount({
   151→				observations: smoothedPurchasesArr.length,
   152→			});
   153→
   154→			const changes = MathematicalFunctions.changePointDetection({
   155→				values: smoothedPurchasesArr,
   156→				significance: 0.02,
   157→				penalty: 0.1,
   158→				minSegmentLength: 40,
   159→			});
   160→
   161→			const yearlyComponent = this.calculateSeasonalComponent({
   162→				values: smoothedPurchasesArr,
   163→				period: 365,
   164→				harmonics,
   165→			});
   166→
   167→			const monthlyComponent = this.calculateSeasonalComponent({
   168→				values: smoothedPurchasesArr,
   169→				period: 30,
   170→				harmonics,
   171→			});
   172→
   173→			const weeklyComponent = this.calculateSeasonalComponent({
   174→				values: smoothedPurchasesArr,
   175→				period: 7,
   176→				harmonics,
   177→			});
   178→
   179→			const quarterlyComponent = this.calculateSeasonalComponent({
   180→				values: smoothedPurchasesArr,
   181→				period: 91,
   182→				harmonics,
   183→			});
   184→
   185→			const trendComponent = this.calculateTrendComponent({
   186→				values: smoothedPurchasesArr,
   187→				changePoints: changes.changePoints,
   188→				startDate: startDate,
   189→				endDate: endDate,
   190→			});
   191→
   192→			const residuals = purchasesArr.map((val, i) => {
   193→				const trend = trendComponent[i] ?? 0;
   194→				const yearly = yearlyComponent[i] ?? 0;
   195→				const monthly = monthlyComponent[i] ?? 0;
   196→				const weekly = weeklyComponent[i] ?? 0;
   197→				const quarterly = quarterlyComponent[i] ?? 0;
   198→				return val - (trend + yearly + monthly + weekly + quarterly);
   199→			});
   200→
   201→			const smoothedResidualsArr = MathematicalFunctions.exponentialSmoothing({
   202→				values: residuals,
   203→				alpha: 0.1,
   204→			});
   205→
   206→			const comprehensiveForecast = this.createComprehensiveForecast({
   207→				yearlyComponent,
   208→				monthlyComponent,
   209→				weeklyComponent,
   210→				quarterlyComponent,
   211→				trendComponent,
   212→				smoothedResidualsArr,
   213→				historicalLength: purchasesArr.length,
   214→				forecastDays,
   215→				endDate,
   216→				purchasesArr,
   217→			});
   218→
   219→			const historicalWindow = 14;
   220→			const historicalOrders = purchasesArr.slice(-historicalWindow);
   221→
   222→			const trendingScoreData = {
   223→				historicalOrders,
   224→				forecastedOrders: comprehensiveForecast.forecastValues,
   225→				trendComponent,
   226→			};
   227→
   228→			const trendingResult =
   229→				TrendingScoreCalculator.calculateTrendingScore(trendingScoreData);
   230→
   231→			const trendScore = trendingResult.trendScore;
   232→
   233→			const { trendingReason } = this.calculateTrendingReason({
   234→				comprehensiveForecast,
   235→				historicalOrders,
   236→				trendComponent,
   237→			});
   238→
   239→			const finalTrendingReason = trendingReason;
   240→
   241→			const forecastResult: CompleteForecastResult = {
   242→				style_id: styleId,
   243→				forecast_dates: comprehensiveForecast.forecastDates,
   244→				predicted_orders: comprehensiveForecast.forecastValues,
   245→				trend_score: Math.round(trendScore * 100) / 100,
   246→				trending_reason: finalTrendingReason,
   247→				purchasesArr,
   248→				smoothedPurchasesArr,
   249→				yearlyComponent,
   250→				monthlyComponent,
   251→				weeklyComponent,
   252→				quarterlyComponent,
   253→				trendComponent,
   254→				smoothedResidualsArr,
   255→				comprehensiveForecast,
   256→				changes,
   257→				startDate,
   258→				endDate,
   259→			};
   260→
   261→			if (bar) {
   262→				bar.increment(1);
   263→			}
   264→
   265→			return forecastResult;
   266→		} catch (error) {
   267→			this.logger.error(
   268→				`Error processing product ${styleId}: ${(error as Error).message}`,
   269→				(error as Error).stack,
   270→			);
   271→			if (bar) {
   272→				bar.increment(1);
   273→			}
   274→			return null;
   275→		}
   276→	}
