   278→	public async saveBatchResults(
   279→		results: CompleteForecastResult[],
   280→		startDate: string,
   281→		endDate: string,
   282→		forecastDays: number,
   283→	): Promise<void> {
   284→		if (results.length === 0) return;
   285→
   286→		try {
   287→			const dbPredictions: ITrendingProductsCreate[] = results
   288→				.map((result) => {
   289→					let predictedOrders = result.predicted_orders;
   290→					let actualForecastDays = forecastDays;
   291→
   292→					if (forecastDays === 9 && predictedOrders.length === 9) {
   293→						predictedOrders = predictedOrders.slice(-7);
   294→						actualForecastDays = 7;
   295→					}
   296→
   297→					const totalPredictedOrders = predictedOrders.reduce(
   298→						(sum, value) => sum + value,
   299→						0,
   300→					);
   301→
   302→					return {
   303→						style_id: result.style_id,
   304→						predicted_orders: predictedOrders,
   305→						total_predicted_orders: totalPredictedOrders,
   306→						trend_score: result.trend_score,
   307→						trending_reason: result.trending_reason,
   308→						forecast_start_date: startDate,
   309→						forecast_end_date: endDate,
   310→						forecast_days: actualForecastDays,
   311→					};
   312→				})
   313→				.filter(
   314→					(data) =>
   315→						typeof data.trend_score === 'number' && !Number.isNaN(data.trend_score),
   316→				);
   317→
   318→			await this.forecastedTrendingProductsService.saveBatchPredictions({
   319→				predictions: dbPredictions,
   320→			});
   321→
   322→			this.logger.log('Successfully saved predictions to database', {
   323→				count: results.length,
   324→				forecastDays,
   325→			});
   326→		} catch (error) {
   327→			this.logger.error(
   328→				`Failed to save batch predictions to database: ${(error as Error).message}`,
   329→				(error as Error).stack,
   330→			);
   331→		}
   332→	}
   333→
   334→	private calculateSeasonalComponent({
   335→		values,
   336→		period,
   337→		harmonics,
   338→	}: {
   339→		values: number[];
   340→		period: number;
   341→		harmonics: number;
   342→	}): number[] {
   343→		const n = values.length;
   344→		if (n < period) {
   345→			return new Array(n).fill(0) as number[];
   346→		}
   347→
   348→		try {
   349→			const coefficients = MathematicalFunctions.fourierCoefficients({
   350→				values,
   351→				period,
   352→				harmonics,
   353→				precision: null,
   354→			});
   355→
   356→			const seasonal = MathematicalFunctions.reconstructFourierSeries({
   357→				period,
   358→				harmonics,
   359→				a: coefficients.a,
   360→				b: coefficients.b,
   361→				length: n,
   362→			});
   363→
   364→			return seasonal;
   365→		} catch (error) {
   366→			this.logger.error(
   367→				`Error extending seasonal component: ${(error as Error).message}`,
   368→				(error as Error).stack,
   369→			);
   370→			return values.map((_, index) => {
   371→				const cyclePosition = index % Math.max(1, Math.floor(period));
   372→				const seasonalIndex = Math.min(cyclePosition, values.length - 1);
   373→				return values[seasonalIndex] ? values[seasonalIndex] * 0.1 : 0;
   374→			});
   375→		}
   376→	}
   377→
   378→	private calculateTrendComponent({
   379→		values,
   380→		changePoints,
   381→		startDate,
   382→		endDate,
   383→	}: {
   384→		values: number[];
   385→		changePoints: number[];
   386→		startDate: string;
   387→		endDate: string;
   388→	}): number[] {
   389→		const n = values.length;
   390→		if (n === 0) return [];
   391→
   392→		const dates = this.generateDateRange(startDate, endDate, n);
   393→
   394→		if (changePoints.length === 0) {
   395→			return MathematicalFunctions.calculateTrend({ values, dates });
   396→		}
   397→
   398→		const trend = new Array(n).fill(0) as number[];
   399→		const segments = [0, ...changePoints, n];
   400→
   401→		for (let i = 0; i < segments.length - 1; i++) {
   402→			const start = segments[i] as unknown as number;
   403→			const end = segments[i + 1] as unknown as number;
   404→			const segmentValues = values.slice(start, end);
   405→			const segmentDates = dates.slice(start, end);
   406→
   407→			if (segmentValues.length > 1) {
   408→				const segmentTrend = MathematicalFunctions.calculateTrend({
   409→					values: segmentValues,
   410→					dates: segmentDates,
   411→				});
   412→
   413→				for (let j = 0; j < segmentTrend.length; j++) {
   414→					trend[start + j] = segmentTrend[j] as unknown as number;
   415→				}
   416→			} else if (segmentValues.length === 1) {
   417→				trend[start] = segmentValues[0] as unknown as number;
   418→			}
   419→		}
   420→
   421→		return trend;
   422→	}
   423→
   424→	private generateDateRange(startDate: string, endDate: string, count: number): string[] {
   425→		const start = new Date(startDate);
   426→		const end = new Date(endDate);
   427→		const totalDays =
   428→			Math.floor((end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24)) + 1;
   429→		const step = totalDays / count;
   430→
   431→		const dates: string[] = [];
   432→		for (let i = 0; i < count; i++) {
   433→			const currentDate = new Date(start.getTime() + i * step * 24 * 60 * 60 * 1000);
   434→			const dateArr = currentDate.toISOString().split('T') as [string, string];
   435→			dates.push(dateArr[0]);
   436→		}
   437→		return dates;
   438→	}
   439→
   440→	private createComprehensiveForecast({
   441→		yearlyComponent,
   442→		monthlyComponent,
   443→		weeklyComponent,
   444→		quarterlyComponent,
   445→		trendComponent,
   446→		smoothedResidualsArr,
   447→		historicalLength,
   448→		forecastDays,
   449→		endDate,
   450→	}: {
   451→		yearlyComponent: number[];
   452→		monthlyComponent: number[];
   453→		weeklyComponent: number[];
   454→		quarterlyComponent: number[];
   455→		trendComponent: number[];
   456→		smoothedResidualsArr: number[];
   457→		historicalLength: number;
   458→		forecastDays: number;
   459→		endDate: string;
   460→		purchasesArr: number[];
   461→	}): {
   462→		forecastValues: number[];
   463→		forecastDates: string[];
   464→		components: {
   465→			yearly: number[];
   466→			monthly: number[];
   467→			weekly: number[];
   468→			quarterly: number[];
   469→			trend: number[];
   470→			residuals: number[];
   471→		};
   472→	} {
   473→		const forecastDates = this.generateFutureDates(endDate, forecastDays);
   474→
   475→		const harmonics = this.getHarmonicsByObservationsCount({
   476→			observations: historicalLength,
   477→		});
   478→
   479→		const extendedYearly = this.extendSeasonalComponent(
   480→			yearlyComponent,
   481→			365,
   482→			harmonics,
   483→			historicalLength,
   484→			forecastDates,
   485→			endDate,
   486→		);
   487→		const extendedMonthly = this.extendSeasonalComponent(
   488→			monthlyComponent,
   489→			30,
   490→			harmonics,
   491→			historicalLength,
   492→			forecastDates,
   493→			endDate,
   494→		);
   495→		const extendedWeekly = this.extendSeasonalComponent(
   496→			weeklyComponent,
   497→			7,
   498→			harmonics,
   499→			historicalLength,
   500→			forecastDates,
   501→			endDate,
   502→		);
   503→		const extendedQuarterly = this.extendSeasonalComponent(
   504→			quarterlyComponent,
   505→			91,
   506→			harmonics,
   507→			historicalLength,
   508→			forecastDates,
   509→			endDate,
   510→		);
   511→
   512→		const extendedResiduals = this.extendResidualsComponent({
   513→			smoothedResidualsArr,
   514→			forecastDays,
   515→			endDate,
   516→		});
   517→
   518→		const extendedTrend = this.extendTrendComponent(trendComponent, forecastDays);
   519→
   520→		const forecastValues = Array(forecastDays)
   521→			.fill(0)
   522→			.map((_, i) => {
   523→				const yearly = extendedYearly[i] ?? 0;
   524→				const monthly = extendedMonthly[i] ?? 0;
   525→				const weekly = extendedWeekly[i] ?? 0;
   526→				const quarterly = extendedQuarterly[i] ?? 0;
   527→				const trend = extendedTrend[i] ?? 0;
   528→				const residual = extendedResiduals[i] ?? 0;
   529→				const forecastValue = trend + yearly + monthly + weekly + quarterly + residual;
   530→				return Math.max(0, forecastValue);
   531→			});
   532→
   533→		return {
   534→			forecastValues,
   535→			forecastDates,
   536→			components: {
   537→				yearly: extendedYearly,
   538→				monthly: extendedMonthly,
   539→				weekly: extendedWeekly,
   540→				quarterly: extendedQuarterly,
   541→				trend: extendedTrend,
   542→				residuals: extendedResiduals,
   543→			},
   544→		};
   545→	}
   546→
   547→	private getHarmonicsByObservationsCount({
   548→		observations,
   549→	}: {
   550→		observations: number;
   551→	}): number {
   552→		if (observations <= 800) return 8;
   553→		return 4;
   554→	}
   555→
   556→	private extendSeasonalComponent(
   557→		component: number[],
   558→		period: number,
   559→		harmonics: number,
   560→		historicalLength: number,
   561→		forecastDates: string[],
   562→		endDate: string,
   563→	): number[] {
   564→		if (component.length === 0) return Array(forecastDates.length).fill(0) as number[];
   565→
   566→		try {
   567→			const coefficients = MathematicalFunctions.fourierCoefficients({
   568→				values: component,
   569→				period,
   570→				harmonics,
   571→				precision: null,
   572→			});
   573→
   574→			const forecastValues: number[] = [];
   575→			const endDateObj = new Date(endDate);
   576→
   577→			for (const forecastDate of forecastDates) {
   578→				const forecastDateObj = new Date(forecastDate);
   579→
   580→				const daysDiff = Math.floor(
   581→					(forecastDateObj.getTime() - endDateObj.getTime()) / (1000 * 60 * 60 * 24),
   582→				);
   583→
   584→				const cyclePosition = (historicalLength + daysDiff) % period;
   585→				const singlePointSeries = MathematicalFunctions.reconstructFourierSeries({
   586→					period,
   587→					harmonics,
   588→					a: coefficients.a,
   589→					b: coefficients.b,
   590→					length: Math.ceil(cyclePosition) + 1,
   591→					a0: 0,
   592→				});
   593→
   594→				const seasonalValue = singlePointSeries[Math.floor(cyclePosition)] ?? 0;
   595→				forecastValues.push(seasonalValue);
   596→			}
   597→
   598→			return forecastValues;
   599→		} catch (error) {
   600→			this.logger.error(
   601→				`Error extending seasonal component: ${(error as Error).message}`,
   602→				(error as Error).stack,
   603→			);
   604→			return forecastDates.map((forecastDate) => {
   605→				const endDateObj = new Date(endDate);
   606→				const forecastDateObj = new Date(forecastDate);
   607→				const daysDiff = Math.floor(
   608→					(forecastDateObj.getTime() - endDateObj.getTime()) / (1000 * 60 * 60 * 24),
   609→				);
   610→				const flooredPeriod = Math.max(1, Math.floor(period));
   611→				const cyclePosition = (historicalLength + daysDiff) % flooredPeriod;
   612→				const historicalIndex = Math.min(cyclePosition, component.length - 1);
   613→				return component[historicalIndex] ?? 0;
   614→			});
   615→		}
   616→	}
   617→
   618→	private extendTrendComponent(trendComponent: number[], forecastDays: number): number[] {
   619→		if (trendComponent.length < 2) return Array(forecastDays).fill(0) as number[];
   620→
   621→		const recentTrendPoints = Math.min(30, trendComponent.length);
   622→		const recentTrend = trendComponent.slice(-recentTrendPoints);
   623→
   624→		const x = Array.from({ length: recentTrend.length }, (_, i) => i);
   625→		const regression = MathematicalFunctions.linearRegression({ x, y: recentTrend });
   626→
   627→		const lastValue = trendComponent[trendComponent.length - 1] ?? 0;
   628→		const trendSlope = regression.slope;
   629→
   630→		return Array(forecastDays)
   631→			.fill(0)
   632→			.map((_, i) => {
   633→				const decay = Math.exp(-0.02 * i);
   634→				return lastValue + trendSlope * (i + 1) * decay;
   635→			});
   636→	}
   637→
   638→	private extendResidualsComponent({
   639→		smoothedResidualsArr,
   640→		forecastDays,
   641→		endDate,
   642→	}: {
   643→		smoothedResidualsArr: number[];
   644→		forecastDays: number;
   645→		endDate: string;
   646→	}): number[] {
   647→		if (smoothedResidualsArr.length === 0 || forecastDays <= 0) {
   648→			return Array(forecastDays).fill(0) as number[];
   649→		}
   650→
   651→		const twoWeeksLength = 7;
   652→		const trendLength = Math.min(twoWeeksLength, smoothedResidualsArr.length);
   653→		const recentResiduals = smoothedResidualsArr.slice(-trendLength);
   654→
   655→		const endDateObj = new Date(endDate);
   656→		const dates = recentResiduals.map((_, i) => {
   657→			const date = new Date(endDateObj);
   658→			date.setDate(endDateObj.getDate() - (trendLength - i - 1));
   659→			const dateArr = date.toISOString().split('T') as [string, string];
   660→			return dateArr[0];
   661→		});
   662→
   663→		const trendValues = MathematicalFunctions.calculateTrend({
   664→			values: recentResiduals,
   665→			dates,
   666→		});
   667→
   668→		if (trendValues.length === 0) {
   669→			return Array(forecastDays).fill(0) as number[];
   670→		}
   671→
   672→		const x = Array.from({ length: recentResiduals.length }, (_, i) => i);
   673→		const regression = MathematicalFunctions.linearRegression({ x, y: recentResiduals });
   674→
   675→		const lastIndex = recentResiduals.length - 1;
   676→		return Array(forecastDays)
   677→			.fill(0)
   678→			.map((_, i) => {
   679→				return regression.slope * (lastIndex + i + 1) + regression.intercept;
   680→			});
   681→	}
   682→
   683→	private getDayOfYear(date = new Date()) {
   684→		const start = new Date(Date.UTC(date.getFullYear(), 0, 1));
   685→		const current = new Date(
   686→			Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()),
   687→		);
   688→
   689→		return Math.floor((current.getTime() - start.getTime()) / (1000 * 60 * 60 * 24)) + 1;
   690→	}
   691→
   692→	private generateFutureDates(endDate: string, forecastDays: number): string[] {
   693→		const dates: string[] = [];
   694→		const startDate = new Date(endDate);
   695→
   696→		for (let i = 1; i <= forecastDays; i++) {
   697→			const futureDate = new Date(startDate);
   698→			futureDate.setDate(startDate.getDate() + i);
   699→			const dateArr = futureDate.toISOString().split('T') as [string, string];
   700→			dates.push(dateArr[0]);
   701→		}
   702→
   703→		return dates;
   704→	}
   705→
   706→	private calculateTrendingReason({
   707→		comprehensiveForecast,
   708→		historicalOrders,
   709→		trendComponent,
   710→	}: {
   711→		comprehensiveForecast: {
   712→			forecastValues: number[];
   713→			forecastDates: string[];
   714→			components: {
   715→				yearly: number[];
   716→				monthly: number[];
   717→				weekly: number[];
   718→				quarterly: number[];
   719→				trend: number[];
   720→				residuals: number[];
   721→			};
   722→		};
   723→		historicalOrders: number[];
   724→		trendComponent: number[];
   725→	}): { trendingReason: string; growthRate: number } {
   726→		if (
   727→			historicalOrders.length === 0 ||
   728→			comprehensiveForecast.forecastValues.length === 0
   729→		) {
   730→			return { trendingReason: 'Stable pattern', growthRate: 0 };
   731→		}
   732→
   733→		const historicalAvg =
   734→			historicalOrders.reduce((sum, val) => sum + val, 0) / historicalOrders.length;
   735→		const forecastAvg =
   736→			comprehensiveForecast.forecastValues.reduce((sum, val) => sum + val, 0) /
   737→			comprehensiveForecast.forecastValues.length;
   738→
   739→		const growthRate =
   740→			historicalAvg > 0 ? (forecastAvg - historicalAvg) / historicalAvg : 0;
   741→
   742→		const trendSlope = this.calculateTrendSlope(trendComponent);
   743→
   744→		if (growthRate > 0.2 || forecastAvg > historicalAvg * 1.2) {
   745→			return { trendingReason: 'Strong growth forecast', growthRate };
   746→		} else if (growthRate > 0.1 || forecastAvg > historicalAvg * 1.1) {
   747→			return { trendingReason: 'Moderate growth forecast', growthRate };
   748→		} else if (growthRate > 0 || trendSlope >= 0.05) {
   749→			return { trendingReason: 'Positive trend detected', growthRate };
   750→		} else {
   751→			return { trendingReason: 'Stable pattern', growthRate };
   752→		}
   753→	}
   754→
   755→	private calculateTrendSlope(trendComponent: number[]): number {
   756→		if (trendComponent.length < 2) return 0;
   757→
   758→		const recentPoints = Math.min(14, trendComponent.length);
   759→		const recentTrend = trendComponent.slice(-recentPoints);
   760→
   761→		const x = Array.from({ length: recentTrend.length }, (_, i) => i);
   762→		const regression = MathematicalFunctions.linearRegression({ x, y: recentTrend });
   763→
   764→		return regression.slope;
   765→	}
   766→}
