    78→					correlatedCategoryIds.push(...correlations.map((corr) => corr.edge_id));
    79→				}
    80→			}
    81→
    82→			correlatedCategoryIds = [...new Set(correlatedCategoryIds)];
    83→			this.logger.debug('Found correlated categories', {
