export class FrequentlyBoughtTogetherQueryDto {
    @ApiProperty({
        description: 'Style IDs for which to find frequently bought together products',
        example: [12345, 67890],
    })
    @Transform(({ value }): number[] => {
        if (typeof value === 'string') {
            return value.split(',').map((id) => parseInt(id.trim(), 10));
        }
        return value as number[];
    })
    @IsArray()
    @IsInt({ each: true, message: 'Each styleId must be an integer' })
    styleIds: number[];

    @ApiProperty({
        description: 'Comma-separated list of style IDs to exclude from results',
        required: false,
        example: '123,456,789',
    })
    @IsOptional()
    @Transform(({ value }): number[] => {
        if (typeof value === 'string') {
            return value.split(',').map((id) => parseInt(id.trim(), 10));
        }
        return value as number[];
    })
